   214→inline int hex_digit_to_int(char c) {
   215→    /* Assume ASCII. */
   216→    assert('0' == 0x30 && 'A' == 0x41 && 'a' == 0x61);
   217→    assert(isxdigit(c));
   218→    int x = static_cast<unsigned char>(c);
