inline int hex_digit_to_int(char c) {
    /* Assume ASCII. */
    assert('0' == 0x30 && 'A' == 0x41 && 'a' == 0x61);
    assert(isxdigit(c));
    int x = static_cast<unsigned char>(c);
    if (x > '9') {
        x += 9;
    }
    return x & 0xf;
}

static int unescape_c_escape_sequences(const char* source, char* dest)
{
    char* d = dest;
    const char* p = source;

    // Small optimization for case where source = dest and there's no escaping
    while ( p == d && *p != '\0' && *p != '\\' ) {
        p++;
        d++;
    }

    while (*p != '\0') {
        if (*p != '\\') {
            *d++ = *p++;
        } else {
            switch ( *++p ) {                    // skip past the '\\'
                case '\0':
                    throw std::runtime_error("bad c-escape string");
                case 'a':  *d++ = '\a';  break;
                case 'b':  *d++ = '\b';  break;
                case 'f':  *d++ = '\f';  break;
                case 'n':  *d++ = '\n';  break;
                case 'r':  *d++ = '\r';  break;
                case 't':  *d++ = '\t';  break;
                case 'v':  *d++ = '\v';  break;
                case '\\': *d++ = '\\';  break;
                case '?':  *d++ = '\?';  break;    // \?  Who knew?
                case '\'': *d++ = '\'';  break;
                case '"':  *d++ = '\"';  break;
                case '0': case '1': case '2': case '3':  // octal digit: 1 to 3 digits
                case '4': case '5': case '6': case '7': {
                    char ch = *p - '0';
                    if ( IS_OCTAL_DIGIT(p[1]) ) {
                        ch = ch * 8 + *++p - '0';
                    }
                    if ( IS_OCTAL_DIGIT(p[1]) ) {      // safe (and easy) to do this twice
                        ch = ch * 8 + *++p - '0';      // now points at last digit
                    }
                    *d++ = ch;
                    break;
                }
                case 'x': case 'X': {
                    if (!isxdigit(p[1])) {
                        if (p[1] == '\0') {
                            throw std::runtime_error("bad c-escape string");
                        }
                        else {
                            throw std::runtime_error("bad c-escape string");
                        }
                        break;
                    }
                    unsigned int ch = 0;
                    while (isxdigit(p[1])) { // arbitrarily many hex digits
                        ch = (ch << 4) + hex_digit_to_int(*++p);
                    }
                    if (ch > 0xFF) {
                        throw std::runtime_error("bad c-escape string");
                    }
                    *d++ = ch;
                    break;
                }
                case 'u': case 'U': {
                    // TODO: support \u and \U ?
                    throw std::runtime_error("bad c-escape string");
                }
                default:
                    throw std::runtime_error("bad c-escape string");
            }
            p++; // read past letter we escaped
        }
    }
    *d = '\0';
    return d - dest;
}

std::string StringUtils::unescape_c_escape_string(const std::string& src)
{
    sofa::pbrpc::scoped_array<char> unescaped(new char[src.size() + 1]);
    int len = unescape_c_escape_sequences(src.c_str(), unescaped.get());
    return std::string(unescaped.get(), len);
}

////////////// xml_escape ///////////////////////////////
void StringUtils::xml_escape_string(std::ostream& os, const char* src, int src_len)
{
    for (int i = 0; i < src_len; ++i) {
        char ch = *(src + i);
        switch (ch) {
            case '&': os << "&amp;"; break;
            case '\'': os << "&apos;"; break;
            case '"': os << "&quot;"; break;
            case '<': os << "&lt;"; break;
            case '>': os << "&gt;"; break;
            default: os << ch;
        }
    }
}

std::string StringUtils::xml_escape_string(const char* src, int src_len)
{
    std::stringstream os;
    xml_escape_string(os, src, src_len);
    return os.str();
}

////////////// json_escape ///////////////////////////////
void StringUtils::json_escape_string(std::ostream& os, const char* src, int src_len)
{
    for (int i = 0; i < src_len; ++i) {
        char c = *(src + i);
        switch (c)
        {
            case '"': os << "\\\""; break;
            case '\\': os  << "\\\\"; break;
            case '/': os << "\\/"; break;
            case '\b': os << "\\b"; break;
            case '\f': os << "\\f"; break;
            case '\n': os << "\\n"; break;
            case '\r': os << "\\r"; break;
            case '\t': os << "\\t"; break;
            case '\0': os << "\\u0000"; break;
            default: os << c;
        }
    }
}

std::string StringUtils::json_escape_string(const char* src, int src_len)
{
    std::stringstream os;
    json_escape_string(os, src, src_len);
    return os.str();
}

